#include <iostream>

class Vec2
{
    int m_x{};
    int m_y{};

public:
    Vec2(int x, int y) : m_x{ x }, m_y{ y } {}

    Vec2 operator-() const { return Vec2{ -m_x, -m_y }; }
    Vec2 operator+() const { return *this; }

    int getX() const { return m_x; }
    int getY() const { return m_y; }
};

int main()
{
    int x{};
    int y{};
    std::cin >> x >> y;

    Vec2 v{ x, y };
    Vec2 neg{ -v };
    Vec2 pos{ +v };

    std::cout << neg.getX() << ' ' << neg.getY() << '\n';
    std::cout << pos.getX() << ' ' << pos.getY() << '\n';

    return 0;
}

