solution_code:
#include <iostream>

class Counter
{
    int m_count{};

public:
    explicit Counter(int count) : m_count{ count } {}

    Counter operator-() const { return Counter{ -m_count }; }
    bool operator!() const { return m_count == 0; }

    int getCount() const { return m_count; }
};

int main()
{
    int n{};
    std::cin >> n;

    Counter c{ n };
    Counter neg{ -c };

    std::cout << neg.getCount() << '\n';
    std::cout << std::boolalpha << !c << '\n';

    return 0;
}
